<?php
namespace Tests\Feature;
use App\Models\AppNotification;use App\Models\AutomationEvent;use App\Models\PurchaseRequest;use App\Models\Rfq;use App\Models\Tenant;use App\Models\User;use App\Services\AutomationService;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\Mail;use Tests\TestCase;
class AutomationWorkflowTest extends TestCase{use RefreshDatabase;public function test_daily_reminders_are_sent_only_once():void{Mail::fake();$tenant=Tenant::query()->create(['name'=>'Alpha','slug'=>'alpha-auto']);$user=User::query()->create(['name'=>'Owner','email'=>'owner-auto@test.dev','password'=>'password','current_tenant_id'=>$tenant->id]);$tenant->users()->attach($user,['role'=>'owner']);$request=PurchaseRequest::query()->create(['tenant_id'=>$tenant->id,'created_by'=>$user->id,'reference'=>'DA-AUTO-1','title'=>'Materiel','service'=>'IT','priority'=>'normal','reason'=>'Besoin','currency'=>'XAF','estimated_amount'=>100000,'status'=>'in_consultation']);Rfq::query()->create(['tenant_id'=>$tenant->id,'purchase_request_id'=>$request->id,'created_by'=>$user->id,'reference'=>'RFQ-AUTO-1','title'=>'Materiel','currency'=>'XAF','response_deadline'=>now()->addDay(),'status'=>'published','required_quote_count'=>1,'competition_method'=>'direct_purchase','published_at'=>now()]);$service=app(AutomationService::class);$first=$service->run($tenant->id);$second=$service->run($tenant->id);$this->assertSame(1,$first['events']);$this->assertSame(0,$second['events']);$this->assertSame(1,AppNotification::query()->count());$this->assertSame(1,AutomationEvent::query()->count());Mail::assertSentCount(1);}}
